import base64, os

TARGET = "/home/hermes/.hermes/workspace/hermes_agents"

FILES = {
    "core/__init__.py": "",
    "ag_01_cacador/__init__.py": "",
    "ag_02_lucratividade/__init__.py": "",
    "ag_03_marketplaces/__init__.py": "",
    "ag_04_planejador/__init__.py": "",
    "ag_05_industrial/__init__.py": "",
    "ag_06_telegram/__init__.py": "",
    "ag_07_laboratorio/__init__.py": "",
    "ag_08_lojas/__init__.py": "",
    "ag_09_memoria/__init__.py": "",
    "ag_10_diretor/__init__.py": "",
    "__init__.py": "",
    "profiles/profiles.yaml": "",
    "sql/schema.sql": "",
}

def deploy():
    for rel_path, b64 in sorted(FILES.items()):
        full_path = os.path.join(TARGET, rel_path.replace("/", os.sep))
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        with open(full_path, "wb") as f:
            f.write(base64.b64decode(b64))
        print(f"  [+] {rel_path}")

if __name__ == "__main__":
    os.makedirs(TARGET, exist_ok=True)
    print(f"Deploying hermes_agents to {TARGET}")
    deploy()
    print(f"\nAll {len(FILES)} files written successfully.")
